// CSS only — JS 불필요
// 패닝 거리 = (130 - 100) / 130 ≈ 23% (자기 폭 기준)
// width를 키울수록 팬이 길어짐 (120~150% 권장)

.card-frame { position: relative; overflow: hidden;
