// CSS only — JS 불필요
// grayscale 대신 sepia(0.6)·saturate(0.2)로 변형 가능
// 부분 해제: grayscale(1) → grayscale(0.2)로 톤 유지

.card-frame { position: relative; overflow: hidden;
  border-radius: 16px; }
.card-tone { position: absolute; inset: 0;
  background: #3b82f6;        /* 브랜드 컬러 */
  mix-blend-mode: color;      /* 또는 multiply */
  opacity: 1; pointer-events: none;
  transition: opacity 0.45s ease; }
.card:hover .card-tone { opacity: 0; }

// CSS only — JS 불필요
// mix-blend-mode: color → 명도 유지 + 색상만 교체 (듀오톤)
// mix-blend-mode: multiply → 어둡게 가라앉는 톤 (디밍 겸용)

.card-frame { position: relative; overflow: hidden;
  border-radius: 16px; }
.card-art { position: absolute; inset: 0;
  background: url(work.jpg) center/cover; }
.card-art { filter: blur(8px); transform: scale(1.08);
  transition: filter 0.55s ease,
    transform 0.55s cubic-bezier(0.33,1,0.68,1); }
.card:hover .card-art { filter: blur(0); transform: scale(1); }

// CSS only — JS 불필요
// scale(1.08) 보정: blur는 가장자리가 투명하게 번지므로
// 블러 상태에서 미리 키워 프레임 밖으로 밀어내 숨긴다

.card-cap { position: absolute; left: 0; right: 0; bottom: 0;
  padding: 18px 16px 16px;
  background: linear-gradient(180deg,
    rgba(0,0,0,0) 0%, rgba(0,0,0,0.9) 100%);
  clip-path: inset(100% 0 0 0);
  transition: clip-path 0.5s cubic-bezier(0.22,1,0.36,1); }
.card:hover .card-cap { clip-path: inset(0 0 0 0); }
.card:hover .card-art { filter: brightness(0.72); }

// CSS only — JS 불필요
// translateY 대신 clip-path를 쓰면 캡션이 프레임 안에서
// "잘려서 나타나는" 마스크 느낌 — overflow 충돌도 없음

.frame-slices { display: flex; overflow: hidden; }
.slice { width: 25%; height: 100%;
  background: url(work.jpg);          /* 같은 아트 공유 */
  background-size: 400% 100%;         /* 4배 폭으로 분담 */
  transition: transform 0.45s cubic-bezier(0.22,1,0.36,1); }
.slice:nth-child(1) { background-position: 0% 0; }
.slice:nth-child(2) { background-position: 33.333% 0; transition-delay: 0.05s; }
.slice:nth-child(3) { background-position: 66.667% 0; transition-delay: 0.1s; }
.slice:nth-child(4) { background-position: 100% 0; transition-delay: 0.15s; }

frame.addEventListener("mousemove", function(e){
  var rect = frame.getBoundingClientRect();
  var nx = ((e.clientX - rect.left) / rect.width - 0.5) * 2;
  for (var i = 0; i < slices.length; i++) {
    var ty = base[i] + nx * 6 * (i - 1.5);  // base = [-16,10,-10,16]
    slices[i].style.transform = "translateY(" + ty + "px)";
  }
});
frame.addEventListener("mouseleave", function(){
  for (var i = 0; i < slices.length; i++) {
    slices[i].style.transform = "translateY(0)";
  }
});

.tilt-frame { will-change: transform; }
.card-glare { position: absolute; inset: -40%;
  background: radial-gradient(circle at 50% 50%,
    rgba(255,255,255,0.32) 0%, rgba(255,255,255,0) 55%);
  opacity: 0; transition: opacity 0.3s ease;
  pointer-events: none; }

frame.addEventListener("mousemove", function(e){
  var rect = frame.getBoundingClientRect();
  var px = (e.clientX - rect.left) / rect.width;   // 0~1
  var py = (e.clientY - rect.top) / rect.height;   // 0~1
  var ry = (px - 0.5) * 16;   // rotateY ±8°
  var rx = (0.5 - py) * 12;   // rotateX ±6°
  frame.style.transition = "transform 0.12s ease-out";
  frame.style.transform = "perspective(700px) rotateX(" + rx
    + "deg) rotateY(" + ry + "deg)";
  glare.style.transform = "translate(" + ((px-0.5)*60) + "%, "
    + ((py-0.5)*60) + "%)";
});
frame.addEventListener("mouseleave", function(){
  frame.style.transition =
    "transform 0.6s cubic-bezier(0.34,1.56,0.64,1)";  // spring
  frame.style.transform = "perspective(700px) rotateX(0) rotateY(0)";
});

.card-frame { position: relative; overflow: hidden;
  border-radius: 16px; background: #0d0d0d;
  border: 1px solid rgba(255,255,255,0);
  transition: border-color 0.4s ease; }
.card-art { position: absolute; inset: 0;
  clip-path: inset(0px round 16px);
  transition: clip-path 0.5s cubic-bezier(0.22,1,0.36,1); }
.card:hover .card-art { clip-path: inset(24px round 6px); }
.card:hover .card-frame { border-color: rgba(255,255,255,0.28); }

// CSS only — JS 불필요
// padding 전환과 달리 clip-path는 레이아웃 리플로우 없이
// 합성 단계에서만 처리 — 60fps 보장

.card-wash { position: absolute; inset: 0;
  display: flex; flex-direction: column;
  justify-content: flex-end; padding: 20px;
  background: linear-gradient(165deg,
    rgba(59,130,246,0.85), rgba(147,51,234,0.88));
  opacity: 0; transition: opacity 0.45s ease; }
.wash-title { transform: translateY(10px); opacity: 0;
  transition: transform 0.45s cubic-bezier(0.22,1,0.36,1) 0.05s,
    opacity 0.4s ease 0.05s; }
.wash-arrow { position: absolute; top: 16px; right: 16px;
  transform: translate(-8px, 8px); opacity: 0;
  transition: transform 0.45s ease 0.12s, opacity 0.4s ease 0.12s; }
.card:hover .card-wash { opacity: 1; }
.card:hover .wash-title { transform: translateY(0); opacity: 1; }
.card:hover .wash-arrow { transform: translate(0, 0); opacity: 1; }

